-- FootManager Online - REAL WORLD SEED
-- 6 Leagues, ~116 Clubs, ~2500 Players (Real Names)
-- ============================================================

-- CLEANUP (remove old seed data if any)
DELETE FROM public.contracts;
DELETE FROM public.stadium_sectors;
DELETE FROM public.financial_transactions;
DELETE FROM public.match_events;
DELETE FROM public.matches;
DELETE FROM public.league_standings;
DELETE FROM public.players;
DELETE FROM public.finances;
DELETE FROM public.club_owners;
DELETE FROM public.clubs;
DELETE FROM public.stadiums;
DELETE FROM public.leagues;

-- ============================================================
-- HELPER FUNCTION
-- ============================================================
CREATE OR REPLACE FUNCTION seed_player(
  p_name TEXT, p_pos TEXT, p_ovr INTEGER, p_nat TEXT,
  p_birth_year INTEGER, p_club_id UUID
) RETURNS VOID AS $$
DECLARE
  v_pid UUID;
  v_pot INTEGER;
  v_age INTEGER;
  v_pac INTEGER; v_sho INTEGER; v_pas INTEGER; v_dri INTEGER; v_def INTEGER; v_phy INTEGER;
  v_salary INTEGER;
  v_market BIGINT;
BEGIN
  v_age := EXTRACT(YEAR FROM CURRENT_DATE)::int - p_birth_year;
  v_pot := LEAST(99, p_ovr + GREATEST(0, (28 - v_age)));
  v_pac := GREATEST(45, LEAST(99, p_ovr + (random()*8-4)::int));
  v_sho := GREATEST(45, LEAST(99, p_ovr + (random()*8-4)::int));
  v_pas := GREATEST(45, LEAST(99, p_ovr + (random()*8-4)::int));
  v_dri := GREATEST(45, LEAST(99, p_ovr + (random()*8-4)::int));
  v_def := GREATEST(45, LEAST(99, p_ovr + (random()*8-4)::int));
  v_phy := GREATEST(45, LEAST(99, p_ovr + (random()*8-4)::int));
  v_salary := (p_ovr * p_ovr * 3);
  v_market := (p_ovr::bigint * p_ovr * p_ovr * 150);
  
  INSERT INTO public.players (name, nationality, birth_date, position, overall, potential,
    pace, shooting, passing, dribbling, defending, physical,
    technique, stamina, experience, morale, fitness,
    market_value, weekly_salary, club_id, status)
  VALUES (p_name, p_nat, make_date(p_birth_year, (random()*11+1)::int, (random()*27+1)::int),
    p_pos, p_ovr, v_pot, v_pac, v_sho, v_pas, v_dri, v_def, v_phy,
    p_ovr, p_ovr, LEAST(100, v_age*3), 70, 100,
    v_market, v_salary, p_club_id, 'active')
  RETURNING id INTO v_pid;
  
  INSERT INTO public.contracts (player_id, club_id, weekly_salary, contract_start, contract_end, is_active)
  VALUES (v_pid, p_club_id, v_salary, CURRENT_DATE - interval '180 days',
    CURRENT_DATE + ((1+(random()*3)::int) * interval '365 days'), true);
END;
$$ LANGUAGE plpgsql;

